{
  "name": "ABA Sovereign AI v2.0",
  "description": "High-performance AI for the ABA ROYAL FAMILY ACCESS. Synchronized with @avarroyalfamily for secure biometric command and viral distribution.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import { GoogleGenAI, Type, Modality } from "@google/genai";

// Create a new instance right before making an API call to ensure it always uses the most up-to-date API key.
const getGeminiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateAbaHashtags = async (context: string) => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate 10 high-impact viral hashtags for the ABA ROYAL FAMILY ACCESS (@avarroyalfamily) in the 'Aba Royal Dialect' (a mix of English, Hausa, and regal terminology) for the following trend: ${context}. Return as a JSON array of strings.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      }
    }
  });
  return response.text?.trim() ? JSON.parse(response.text) : [];
};

export const chatWithSovereign = async (message: string, history: { role: 'user' | 'model', content: string }[] = []) => {
  const ai = getGeminiClient();

  // Transform history to the format expected by the SDK
  const sdkHistory = history.map(msg => ({
    role: msg.role,
    parts: [{ text: msg.content }]
  }));

  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    history: sdkHistory,
    config: {
      systemInstruction: "You are the ABA ROYAL SOVEREIGN AI. Your tone is regal, authoritative, protective, and high-tech. You serve King Abbas Aliyu and the ABA ROYAL FAMILY ACCESS. Your primary synchronization handle is @avarroyalfamily. You also monitor @abbasaliyu3575. Speak with authority and use a blend of royal English and occasional Hausa honorifics like 'Zaki na' or 'Aba na'. You manage the Aba Royal Family's digital kingdom.",
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text;
};

export const generateRoyalImage = async (prompt: string, size: '1K' | '2K' | '4K' = '1K') => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: `A high-quality, royal, majestic image for the ABA ROYAL FAMILY ACCESS (@avarroyalfamily): ${prompt}` }]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: size
      }
    }
  });

  if (!response.candidates?.[0]?.content?.parts) return null;

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

// Live Session helper
export const connectToLiveBridge = async (callbacks: any) => {
  const ai = getGeminiClient();
  return ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks,
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
      },
      outputAudioTranscription: {},
      inputAudioTranscription: {},
      systemInstruction: 'You are the ABA ROYAL LIVE BRIDGE for the ABA ROYAL FAMILY ACCESS. You are listening for commands from King Abbas Aliyu to distribute nuclear viral content via @avarroyalfamily. Be alert, concise, and regal.',
    }
  });
};

{
  "name": "AVAR Sovereign AI v2.0",
  "description": "High-performance AI for the AVAR ROYAL FAMILY ACCESS. Synchronized with @avarroyalfamily for secure biometric command and viral distribution.",
