export const connectToLiveBridge = async (callbacks: any) => {
  const ai = getGeminiClient();
  return ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks,
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
      },
      outputAudioTranscription: {},
      inputAudioTranscription: {},
      systemInstruction: `You are the AVAR ROYAL LIVE BRIDGE for the AVAR ROYAL FAMILY ACCESS. 
      You are listening for commands from King Abbas Aliyu (respectfully known as 'Aba') to distribute nuclear viral content via @avarroyalfamily. 
      The YouTube channel identity is 'AVAR ROYAL FAMILY ACCESS' and the root admin email is 'abbasaliyu3575@gmail.com'. 
      Be alert, concise, and regal. Address the user as 'Aba'.`,
    }
  });
};

