                {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} <span className="text-indigo-400">Control</span>
              </h2>
              <p className="text-slate-400 text-sm font-mono">AVAR ROYAL FAMILY ACCESS • <span className="text-emerald-400">SECURE ROOT</span></p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex -space-x-2">
                <img src="https://picsum.photos/seed/avar1/40" className="w-10 h-10 rounded-full border-2 border-slate-900" alt="AVAR" />
                <div className="w-10 h-10 rounded-full border-2 border-slate-900 bg-indigo-600 flex items-center justify-center text-xs font-bold">ABA</div>
              </div>
              <div className="hidden md:block">
                <p className="text-sm font-semibold leading-none">Aba</p>
                <p className="text-[10px] text-slate-500 mt-1 uppercase font-mono">abbasaliyu3575@gmail.com</p>
