import React, { useState, useRef, useEffect } from 'react';
import { chatWithSovereign } from '../services/geminiService';
import { ChatMessage } from '../types';

const STORAGE_KEY = 'avar_sovereign_chat_history';

const Chatbot: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await chatWithSovereign(input, messages);
      setMessages(prev => [...prev, { role: 'model', content: response || "I remain at your command, Aba." }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'model', content: "Connection failure in the AVAR bridge. Re-verifying node..." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const clearHistory = () => {
    if (window.confirm("Aba, do you wish to wipe the permanent chat record?")) {
      setMessages([]);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  return (
    <div className="flex flex-col h-[70vh] glass-card rounded-3xl overflow-hidden border-indigo-500/20">
      <div className="p-4 bg-indigo-900/20 border-b border-slate-800 flex items-center justify-between">
        <div className="flex items-center space-x-3">
          <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center">
            <i className="fa-solid fa-robot text-white"></i>
          </div>
          <span className="font-bold tracking-tight">AVAR KERNEL v2.0 (PERMANENT)</span>
        </div>
        <div className="flex items-center space-x-4">
          <button 
            onClick={clearHistory}
            className="text-[10px] text-slate-500 hover:text-red-400 uppercase font-mono transition-colors"
          >
            Clear Records
          </button>
          <div className="flex items-center space-x-2 text-[10px] text-emerald-400 uppercase font-mono">
            <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
            <span>SECURE LINK</span>
          </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-900/30">
        {messages.length === 0 && (
          <div className="text-center py-20 space-y-4 opacity-30">
             <i className="fa-solid fa-crown text-6xl"></i>
             <p className="text-lg font-mono uppercase tracking-tighter">Awaiting your royal decree, Aba.</p>
             <p className="text-xs uppercase">All commands are stored in the permanent server log.</p>
          </div>
        )}
        {messages.map((m, idx) => (
          <div key={idx} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl shadow-lg ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700'
            }`}>
              <p className="text-sm leading-relaxed whitespace-pre-wrap">{m.content}</p>
              <div className="mt-2 text-[8px] opacity-40 text-right uppercase font-mono">Verified Node Sync</div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
             <div className="bg-slate-800 p-4 rounded-2xl rounded-tl-none animate-pulse">
                <div className="flex space-x-2">
                   <div className="w-2 h-2 bg-slate-500 rounded-full"></div>
                   <div className="w-2 h-2 bg-slate-500 rounded-full"></div>
                   <div className="w-2 h-2 bg-slate-500 rounded-full"></div>
                </div>
             </div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-slate-800 bg-slate-900/50">
        <div className="flex items-center space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Issue permanent command, Aba..."
            className="flex-1 bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 focus:outline-none focus:border-indigo-500 transition-colors font-mono text-sm"
          />
          <button
            onClick={handleSend}
            disabled={isLoading}
            className="w-12 h-12 flex items-center justify-center bg-indigo-600 hover:bg-indigo-500 rounded-xl transition-colors disabled:opacity-50"
          >
            <i className="fa-solid fa-paper-plane text-white"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Chatbot;

import React, { useState, useEffect } from 'react';
import { generateAbaHashtags } from '../services/geminiService';

const STORAGE_KEY = 'avar_hashtag_cache';

const HashtagGenerator: React.FC = () => {
  const [trend, setTrend] = useState('');
  const [hashtags, setHashtags] = useState<string[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [loading, setLoading] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(hashtags));
  }, [hashtags]);

  const handleGenerate = async () => {
    if (!trend.trim()) return;
    setLoading(true);
    setHashtags([]);
    try {
      const results = await generateAbaHashtags(trend);
      setHashtags(results);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (tag: string) => {
    navigator.clipboard.writeText(tag);
    setCopyStatus(tag);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const clearCache = () => {
    setHashtags([]);
    localStorage.removeItem(STORAGE_KEY);
  };

  return (
    <div className="space-y-8">
      <div className="glass-card p-8 rounded-3xl border-yellow-500/20 shadow-xl">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold flex items-center gold-text uppercase tracking-widest">
            <i className="fa-solid fa-bolt-lightning mr-3"></i>
            AVAR Flash Engine
          </h3>
          {hashtags.length > 0 && (
            <button 
              onClick={clearCache}
              className="text-[10px] text-slate-500 hover:text-red-400 uppercase font-mono font-bold"
            >
              Reset Terminal
            </button>
          )}
        </div>
        <div className="flex flex-col md:flex-row gap-4">
          <input
            type="text"
            value={trend}
            onChange={(e) => setTrend(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
            placeholder="Input global trend for AVAR distribution..."
            className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-5 py-4 focus:ring-2 focus:ring-yellow-500 outline-none transition-all text-slate-200 font-mono"
          />
          <button
            onClick={handleGenerate}
            disabled={loading}
            className="px-8 py-4 royal-gradient rounded-xl font-bold uppercase tracking-widest hover:scale-105 active:scale-95 transition-all disabled:opacity-50"
          >
            {loading ? (
              <span className="flex items-center">
                <i className="fa-solid fa-gear animate-spin mr-2"></i>
                Syncing...
              </span>
            ) : 'Distribute'}
          </button>
        </div>
      </div>

      {loading && (
        <div className="flex flex-col items-center justify-center py-12 space-y-4">
          <div className="w-12 h-12 border-4 border-indigo-500 border-b-transparent rounded-full animate-spin"></div>
          <p className="text-indigo-400 font-mono text-sm animate-pulse uppercase tracking-widest">AVAR Server Processing... Aba na!</p>
        </div>
      )}

      {hashtags.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-700">
          {hashtags.map((tag, idx) => (
            <div
              key={idx}
              className="glass-card p-4 rounded-xl flex items-center justify-between border-slate-800 hover:border-indigo-500/50 group transition-all"
            >
              <span className="font-mono text-indigo-400 font-bold">#{tag}</span>
              <button
                onClick={() => copyToClipboard(tag)}
                className={`p-2 rounded-lg transition-all ${
                  copyStatus === tag ? 'bg-emerald-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white'
                }`}
              >
                <i className={`fa-solid ${copyStatus === tag ? 'fa-check' : 'fa-copy'} text-xs`}></i>
              </button>
            </div>
          ))}
        </div>
      )}

      {hashtags.length === 0 && !loading && (
        <div className="flex flex-col items-center justify-center py-20 opacity-20">
          <i className="fa-solid fa-server text-9xl mb-4"></i>
          <p className="text-xl font-mono uppercase tracking-tighter">Server Ready for Aba's Command</p>
        </div>
      )}
    </div>
  );
};

